body.script:
var vbAllPosts=[];var vbCurrentPage=1;var vbPostsPerPage=15;var lastLoggedActivity=null;function triggerVbulletinReply(){var commentArea=document.getElementById('vb-toggle-comment-area');if(!commentArea)return;if(commentArea.classList.contains('form-active')){commentArea.classList.remove('form-active');}else{commentArea.classList.add('form-active');showLiveNotification("Cevap Paneli Açıldı","Lütfen forum kurallarına uygun bir şekilde cevabınızı yazın.");setTimeout(function(){commentArea.scrollIntoView({behavior:'smooth',block:'center'});},150);}}
function showLiveNotification(title,desc){var box=document.getElementById('forumLiveNotification');var tEl=document.getElementById('notifyTitle');var dEl=document.getElementById('notifyDesc');if(box&&tEl&&dEl){tEl.innerText=title;dEl.innerText=desc;box.style.display='flex';setTimeout(function(){box.style.display='none';},6000);}}
function formatForumDate(dateStr){var d=new Date(dateStr);var today=new Date();if(d.toDateString()===today.toDateString()){return'Bugün '+d.getHours().toString().padStart(2,'0')+':'+d.getMinutes().toString().padStart(2,'0');}
var months=["Oca","Şub","Mar","Nis","May","Haz","Tem","Ağu","Eyl","Eki","Kas","Ara"];return d.getDate()+' '+months[d.getMonth()]+' '+d.getFullYear()+', '+d.getHours().toString().padStart(2,'0')+':'+d.getMinutes().toString().padStart(2,'0');}
function cleanAuthorName(name){return(!name||["Anonymous","İsimsiz","anonymous"].includes(name))?"Misafir":name;}
function safeText(str){var div=document.createElement('div');div.textContent=str;return div.innerHTML;}
function renderVbPage(page){var target=document.getElementById('vb-last-posts-target');if(!target||vbAllPosts.length===0)return;var start=(page-1)*vbPostsPerPage;var end=start+vbPostsPerPage;var pagePosts=vbAllPosts.slice(start,end);var html='';pagePosts.forEach(function(p){html+='<div class="hamdi-forum-row">'+'  <div class="hamdi-avatar-holder">'+'    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="2.5"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg>'+'    <div class="hamdi-status-dot"></div>'+'  </div>'+'  <div class="hamdi-main-info">'+'    <div class="hamdi-title"><a href="'+p.link+'">'+p.title+'</a></div>'+'    <div class="hamdi-meta">'+'      <span class="hamdi-author">'+safeText(p.author)+'</span>, '+p.date+'    </div>'+'  </div>'+'  <div class="hamdi-replies-zone">Cevap: ('+p.replies+')</div>'+'  <div class="hamdi-arrow-zone">'+'    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><polyline points="9 18 15 12 9 6"></polyline></svg>'+'  </div>'+'</div>';});target.innerHTML=html;var totalPages=Math.ceil(vbAllPosts.length/vbPostsPerPage);document.getElementById('vb-page-info-text').innerText="Sayfa "+page+" / "+totalPages;document.getElementById('vb-prev-btn').disabled=(page===1);document.getElementById('vb-next-btn').disabled=(page===totalPages);if(totalPages>1){document.getElementById('vb-pagination-ctrl').style.display='flex';}}
function changeVbPage(direction){var totalPages=Math.ceil(vbAllPosts.length/vbPostsPerPage);var nextPage=vbCurrentPage+direction;if(nextPage>=1&&nextPage<=totalPages){vbCurrentPage=nextPage;renderVbPage(vbCurrentPage);document.getElementById('vb-last-posts-target').scrollIntoView({behavior:'smooth',block:'start'});}}
function updateBloggerStats(){var rawViewsEl=document.getElementById('blogger-raw-total-views');var targetViewsEl=document.getElementById('stat-total-views');if(rawViewsEl&&targetViewsEl){var rawText=rawViewsEl.innerText.trim();var count=parseInt(rawText.replace(/[^0-9]/g,''),10);if(!isNaN(count)&&count>0){targetViewsEl.innerText=count.toLocaleString('tr-TR');}else{targetViewsEl.innerText="0";}}
var targetOnlineEl=document.querySelector('.stat-online-count');if(targetOnlineEl){var randomOnline=Math.floor(Math.random()*(410-210+1))+210;targetOnlineEl.innerText=randomOnline+" Kullanıcı Aktif";}}
function loadForumSystem(){var target=document.getElementById('vb-last-posts-target');if(!target)return;var feedUrl="/feeds/posts/summary?alt=json&amp;max-results=999999";var commentUrl="/feeds/comments/default?alt=json&amp;max-results=1";fetch(feedUrl).then(function(res){return res.json();}).then(function(data){var entries=data.feed.entry||[];var totalPosts=data.feed.openSearch$totalResults?data.feed.openSearch$totalResults.$t:entries.length;if(document.getElementById('stat-total-posts')){document.getElementById('stat-total-posts').innerText=Number(totalPosts).toLocaleString('tr-TR');}
if(entries.length===0){target.innerHTML='<div style="padding:25px; text-align:center; color:#64748b;">Henüz açılmış forum konusu bulunmuyor.</div>';return;}
var categoryMap={};vbAllPosts=[];entries.forEach(function(e){var title=safeText(e.title.$t);var link="#";var altLink=e.link.find(function(l){return l.rel==='alternate';});if(altLink)link=altLink.href;var author="Misafir";if(e.author&&e.author[0]&&e.author[0].name){author=cleanAuthorName(e.author[0].name.$t);}
var pubDateFormatted=formatForumDate(e.published.$t);var commentsCount="0";if(e.thr$total){commentsCount=e.thr$total.$t;}
var postObj={title:title,link:link,author:author,date:pubDateFormatted,replies:commentsCount};vbAllPosts.push(postObj);if(e.category){e.category.forEach(function(cat){if(!categoryMap[cat.term]){categoryMap[cat.term]=postObj;}});}});vbCurrentPage=1;renderVbPage(vbCurrentPage);if(entries[0]){var latestId=entries[0].id.$t;if(lastLoggedActivity&&lastLoggedActivity!==latestId){showLiveNotification("Yeni Forum Konusu!",entries[0].title.$t);}
lastLoggedActivity=latestId;if(document.getElementById('stat-last-topic')){var altLinkObj=entries[0].link.find(function(l){return l.rel==='alternate';});var lastLink=altLinkObj?altLinkObj.href:"#";var firstAuthor=(entries[0].author&&entries[0].author[0]&&entries[0].author[0].name)?entries[0].author[0].name.$t:"Misafir";document.getElementById('stat-last-topic').innerHTML='<strong style="color:inherit;">'+safeText(cleanAuthorName(firstAuthor))+'</strong> - <a href="'+lastLink+'" style="display:inline; color:var(--vbulletin-link);">'+safeText(entries[0].title.$t)+'</a>';}}
document.querySelectorAll('.class-target-label-box').forEach(function(box){var labelName=box.getAttribute('data-label');var container=box.querySelector('.cat-last-post-box');if(!container)return;if(categoryMap[labelName]){var cData=categoryMap[labelName];container.innerHTML='Son Konu: <a class="cat-last-title" href="'+cData.link+'">'+cData.title+'</a>'+'<div class="cat-last-meta">Gönderen: <strong style="opacity:0.9;">'+safeText(cData.author)+'</strong> &#8212; '+cData.date+'</div>';}else{container.innerHTML='<span style="color:#94a3b8; font-style:italic;">Bu kategoride henüz konu yok.</span>';}});}).catch(function(err){console.error("Feed hatası:",err);target.innerHTML='<div style="padding:25px; text-align:center; color:#ef4444;">Sistem yüklenirken bir hata oluştu.</div>';});fetch(commentUrl).then(function(res){return res.json();}).then(function(data){var totalComments=data.feed.openSearch$totalResults?data.feed.openSearch$totalResults.$t:"0";if(document.getElementById('stat-total-comments')){document.getElementById('stat-total-comments').innerText=Number(totalComments).toLocaleString('tr-TR');}
var entries=data.feed.entry||[];if(entries.length>0&&document.getElementById('stat-last-reply')){var commAuthor=(entries[0].author&&entries[0].author[0]&&entries[0].author[0].name)?cleanAuthorName(entries[0].author[0].name.$t):"Misafir";var commSummary=entries[0].summary?entries[0].summary.$t:(entries[0].content?entries[0].content.$t:"");commSummary=commSummary.replace(/<\/?[^>]+(>|$)/g,"");if(commSummary.length>60)commSummary=commSummary.substring(0,60)+"...";document.getElementById('stat-last-reply').innerHTML='<strong style="color:inherit;">'+safeText(commAuthor)+'</strong> - <span style="font-style:italic; opacity:0.95;">"'+safeText(commSummary)+'"</span>';}}).catch(function(err){console.error("Yorum hatası:",err);});}
document.addEventListener('DOMContentLoaded',function(){loadForumSystem();setTimeout(updateBloggerStats,600);});
